<?php
$configPath = __DIR__ . '/config.php';
if (!file_exists($configPath)) { die('Falta dashboard/config.php'); }
$config = require $configPath;
$dsn = sprintf('mysql:host=%s;port=%s;dbname=%s;charset=%s', $config['db_host'], $config['db_port'], $config['db_name'], $config['charset']);
$pdo = new PDO($dsn, $config['db_user'], $config['db_pass'], [PDO::ATTR_ERRMODE=>PDO::ERRMODE_EXCEPTION, PDO::ATTR_DEFAULT_FETCH_MODE=>PDO::FETCH_ASSOC]);
$pdo->exec('SET NAMES utf8mb4 COLLATE utf8mb4_unicode_ci');
function h($v){ return htmlspecialchars((string)$v, ENT_QUOTES, 'UTF-8'); }
function q($pdo,$sql,$p=[]){ $s=$pdo->prepare($sql); $s->execute($p); return $s->fetchAll(); }
function one($pdo,$sql,$p=[]){ $r=q($pdo,$sql,$p); return $r[0] ?? null; }
function x($pdo,$sql,$p=[]){ $s=$pdo->prepare($sql); $s->execute($p); }
function csv_out($value){ return mb_convert_encoding((string)$value, 'UTF-8', 'UTF-8'); }

$pdo->exec("CREATE TABLE IF NOT EXISTS dinsec_document_sources (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, document_name VARCHAR(180) NOT NULL, document_date DATE NULL, uploaded_file_name VARCHAR(220) NULL, notes VARCHAR(255) NULL, created_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, UNIQUE KEY uq_dinsec_source (document_name, document_date)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci");
$pdo->exec("INSERT IGNORE INTO dinsec_document_sources (document_name, document_date, uploaded_file_name, notes) VALUES ('COMPOSICION OFICIALES DINSEC POR ZONAS Y SERVICIOS POLICIALES','2025-08-04','COMPOSICIÓN OFICIALES 04AGO25 DINSEC.pdf','Documento de referencia para validacion')");
$pdo->exec("CREATE TABLE IF NOT EXISTS dinsec_personnel_reference (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, source_id BIGINT UNSIGNED NOT NULL, page_number INT NULL, row_number INT NULL, zone_label VARCHAR(180) NULL, zone_unit_id BIGINT UNSIGNED NULL, area_code VARCHAR(10) NULL, area_name VARCHAR(120) NULL, location_sector VARCHAR(180) NULL, direction_label VARCHAR(220) NULL, direction_unit_id BIGINT UNSIGNED NULL, service_label VARCHAR(180) NULL, op_status ENUM('OP','NO OP','OA','NO DEFINIDO') NOT NULL DEFAULT 'NO DEFINIDO', rank_text VARCHAR(80) NULL, position_number VARCHAR(50) NULL, full_name VARCHAR(180) NOT NULL, assignment_text VARCHAR(220) NULL, observation_text VARCHAR(220) NULL, raw_text TEXT NULL, matched_employee_id BIGINT UNSIGNED NULL, review_status ENUM('pendiente','validado','ignorado') NOT NULL DEFAULT 'pendiente', review_notes VARCHAR(255) NULL, created_by VARCHAR(100) NULL DEFAULT 'dashboard', created_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, INDEX idx_dinsec_source (source_id), INDEX idx_dinsec_zone (zone_unit_id), INDEX idx_dinsec_area (area_code, area_name), INDEX idx_dinsec_direction (direction_unit_id), INDEX idx_dinsec_position (position_number), INDEX idx_dinsec_name (full_name), INDEX idx_dinsec_review (review_status)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci");
$source = one($pdo, "SELECT id FROM dinsec_document_sources WHERE document_date='2025-08-04' LIMIT 1");
$msg=''; $err='';
if (($_GET['descargar'] ?? '') === 'csv') {
    $rows = q($pdo, "SELECT id, page_number, row_number, zone_label, area_code, area_name, location_sector, direction_label, service_label, op_status, rank_text, position_number, full_name, assignment_text, observation_text, review_status, created_at FROM dinsec_personnel_reference ORDER BY id DESC");
    header('Content-Type: text/csv; charset=utf-8');
    header('Content-Disposition: attachment; filename=referencia_personal_dinsec.csv');
    $out = fopen('php://output', 'w');
    fputcsv($out, ['ID','Pagina','Fila','Zona','Area','Area nombre','Ubicacion/Sector','Direccion','Servicio','OP/NO OP','Rango','Posicion','Nombre','Asignacion','Observacion','Estado','Fecha']);
    foreach ($rows as $r) { fputcsv($out, array_map('csv_out', $r)); }
    fclose($out); exit;
}
try {
    if ($_SERVER['REQUEST_METHOD']==='POST') {
        $accion = $_POST['accion'] ?? '';
        if ($accion === 'guardar') {
            $zoneUnitId = (int)($_POST['zone_unit_id'] ?? 0);
            $directionUnitId = (int)($_POST['direction_unit_id'] ?? 0);
            $zona = $zoneUnitId ? one($pdo, 'SELECT name FROM organizational_units WHERE id=:id', ['id'=>$zoneUnitId]) : null;
            $dir = $directionUnitId ? one($pdo, 'SELECT name FROM organizational_units WHERE id=:id', ['id'=>$directionUnitId]) : null;
            x($pdo, "INSERT INTO dinsec_personnel_reference (source_id, page_number, row_number, zone_label, zone_unit_id, area_code, area_name, location_sector, direction_label, direction_unit_id, service_label, op_status, rank_text, position_number, full_name, assignment_text, observation_text, raw_text, review_status, review_notes) VALUES (:source_id,:page_number,:row_number,:zone_label,:zone_unit_id,:area_code,:area_name,:location_sector,:direction_label,:direction_unit_id,:service_label,:op_status,:rank_text,:position_number,:full_name,:assignment_text,:observation_text,:raw_text,'pendiente',:review_notes)", [
                'source_id'=>$source['id'], 'page_number'=>(int)($_POST['page_number'] ?? 0) ?: null, 'row_number'=>(int)($_POST['row_number'] ?? 0) ?: null,
                'zone_label'=>$zona['name'] ?? trim($_POST['zone_label'] ?? ''), 'zone_unit_id'=>$zoneUnitId ?: null,
                'area_code'=>trim($_POST['area_code'] ?? ''), 'area_name'=>trim($_POST['area_name'] ?? ''), 'location_sector'=>trim($_POST['location_sector'] ?? ''),
                'direction_label'=>$dir['name'] ?? trim($_POST['direction_label'] ?? ''), 'direction_unit_id'=>$directionUnitId ?: null,
                'service_label'=>trim($_POST['service_label'] ?? ''), 'op_status'=>$_POST['op_status'] ?? 'NO DEFINIDO',
                'rank_text'=>trim($_POST['rank_text'] ?? ''), 'position_number'=>trim($_POST['position_number'] ?? ''), 'full_name'=>trim($_POST['full_name'] ?? ''),
                'assignment_text'=>trim($_POST['assignment_text'] ?? ''), 'observation_text'=>trim($_POST['observation_text'] ?? ''), 'raw_text'=>trim($_POST['raw_text'] ?? ''), 'review_notes'=>trim($_POST['review_notes'] ?? '')
            ]);
            $msg='Referencia DINSEC guardada. No se modifico RRHH.';
        }
        if ($accion === 'estado') {
            x($pdo, "UPDATE dinsec_personnel_reference SET review_status=:estado, review_notes=:nota, updated_at=NOW() WHERE id=:id", ['estado'=>$_POST['estado'], 'nota'=>trim($_POST['nota'] ?? ''), 'id'=>(int)$_POST['id']]);
            $msg='Estado actualizado.';
        }
    }
} catch(Throwable $e){ $err=$e->getMessage(); }
$zonaJoin = "BINARY ou.legacy_table=BINARY 'MOI_CABECERA_ZONA'";
$dirJoin = "BINARY ou.legacy_table=BINARY 'MOI_CABECERA_DIRECCION'";
$zonas = q($pdo, "SELECT id, name FROM organizational_units ou WHERE $zonaJoin AND lifecycle_status='vigente' ORDER BY CAST(legacy_id AS UNSIGNED)");
$direcciones = q($pdo, "SELECT id, name FROM organizational_units ou WHERE $dirJoin AND lifecycle_status='vigente' ORDER BY CAST(legacy_id AS UNSIGNED)");
$buscar = trim($_GET['buscar'] ?? '');
$params=[]; $where='';
if ($buscar !== '') { $where = "WHERE full_name LIKE :b OR position_number LIKE :b OR assignment_text LIKE :b OR location_sector LIKE :b OR zone_label LIKE :b"; $params['b']='%'.$buscar.'%'; }
$registros = q($pdo, "SELECT * FROM dinsec_personnel_reference $where ORDER BY id DESC LIMIT 100", $params);
$resumen = q($pdo, "SELECT COALESCE(zone_label,'SIN ZONA') zona, COALESCE(area_code,'') area, COALESCE(location_sector,'') sector, op_status, review_status, COUNT(*) total FROM dinsec_personnel_reference GROUP BY zone_label, area_code, location_sector, op_status, review_status ORDER BY zona, area, sector LIMIT 80");
?>
<!doctype html><html lang="es"><head><meta charset="utf-8"><title>DINSEC personal referencia</title><style>body{font-family:Arial;margin:0;background:#f4f6f8;color:#1f2937}header{background:#111827;color:white;padding:18px 28px}main{padding:20px}.grid{display:grid;grid-template-columns:360px 1fr;gap:18px}.card,section{background:white;border-radius:10px;padding:14px;box-shadow:0 1px 4px #0002;margin-bottom:16px}.top a{color:#d1d5db;margin-right:14px}input,select,textarea,button{padding:7px;border:1px solid #d1d5db;border-radius:6px;width:100%;box-sizing:border-box}button,.btn{background:#047857;color:white;text-decoration:none;border-radius:6px;padding:8px;display:inline-block;width:auto}table{width:100%;border-collapse:collapse;font-size:13px}th,td{border-bottom:1px solid #e5e7eb;text-align:left;padding:7px;vertical-align:top}th{background:#f9fafb}.msg{background:#ecfdf5;border:1px solid #10b981;padding:10px;border-radius:8px}.err{background:#fef2f2;border:1px solid #ef4444;padding:10px;border-radius:8px}.muted{font-size:12px;color:#6b7280}.row{display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-bottom:8px}</style></head><body><header><h1>Referencia de personal DINSEC</h1><p class="top"><a href="index.php">Dashboard</a><a href="asignar_areas.php">Areas</a><a href="dinsec_personal.php">DINSEC personal</a></p></header><main><?php if($msg):?><p class="msg"><?=h($msg)?></p><?php endif;?><?php if($err):?><p class="err"><?=h($err)?></p><?php endif;?><p><a class="btn" href="?descargar=csv">Descargar CSV</a></p><div class="grid"><section><h2>Paso 1: Capturar referencia del PDF</h2><p class="muted">Esto solo guarda lo que dice el documento DINSEC. No cambia RRHH, no cambia legacy.</p><form method="post"><input type="hidden" name="accion" value="guardar"><div class="row"><label>Pagina PDF<input name="page_number" type="number"></label><label>Fila<input name="row_number" type="number"></label></div><label>Zona<select name="zone_unit_id"><option value="0">Seleccione</option><?php foreach($zonas as $z):?><option value="<?=h($z['id'])?>"><?=h($z['name'])?></option><?php endforeach;?></select></label><div class="row"><label>Area<select name="area_code"><option value="">N/A</option><?php foreach(range('A','P') as $a):?><option value="<?=h($a)?>">Area <?=h($a)?></option><?php endforeach;?></select></label><label>Ubicacion/Sector<input name="location_sector" placeholder="Penonome, Coclesito, Sabanitas..."></label></div><label>Nombre de area<input name="area_name" placeholder="Area A, Area B..."></label><label>Direccion funcional<select name="direction_unit_id"><option value="0">No aplica</option><?php foreach($direcciones as $d):?><option value="<?=h($d['id'])?>"><?=h($d['name'])?></option><?php endforeach;?></select></label><label>Servicio<input name="service_label" placeholder="LINCE, Turismo, Seguridad Ciudadana..."></label><div class="row"><label>OP/NO OP<select name="op_status"><option>NO DEFINIDO</option><option>OP</option><option>NO OP</option><option>OA</option></select></label><label>Rango<input name="rank_text" placeholder="TTE., MAYOR..."></label></div><div class="row"><label>Posicion<input name="position_number"></label><label>Nombre completo<input name="full_name" required></label></div><label>Asignacion<input name="assignment_text" placeholder="AREA A PENONOME"></label><label>Observacion<input name="observation_text" placeholder="VAC. POR JUBILACION, ADMINISTRATIVO..."></label><label>Texto original<textarea name="raw_text" rows="3"></textarea></label><label>Nota de revision<textarea name="review_notes" rows="2"></textarea></label><button>Guardar referencia</button></form></section><section><h2>Resumen capturado</h2><table><thead><tr><th>Zona</th><th>Area</th><th>Sector</th><th>OP</th><th>Estado</th><th>Total</th></tr></thead><tbody><?php foreach($resumen as $r):?><tr><td><?=h($r['zona'])?></td><td><?=h($r['area'])?></td><td><?=h($r['sector'])?></td><td><?=h($r['op_status'])?></td><td><?=h($r['review_status'])?></td><td><?=h($r['total'])?></td></tr><?php endforeach;?></tbody></table></section></div><section><h2>Registros recientes</h2><form method="get" style="margin-bottom:10px"><input name="buscar" value="<?=h($buscar)?>" placeholder="Buscar nombre, posicion, asignacion o zona"><button>Buscar</button></form><table><thead><tr><th>Persona</th><th>Zona / Area / Sector</th><th>Direccion / Servicio</th><th>PDF</th><th>Estado</th><th>Accion</th></tr></thead><tbody><?php foreach($registros as $r):?><tr><td><b><?=h($r['rank_text'])?> <?=h($r['position_number'])?> <?=h($r['full_name'])?></b><br><span class="muted"><?=h($r['assignment_text'])?> <?=h($r['observation_text'])?></span></td><td><?=h($r['zone_label'])?><br>Area <?=h($r['area_code'])?> <?=h($r['location_sector'])?></td><td><?=h($r['direction_label'])?><br><?=h($r['service_label'])?> / <?=h($r['op_status'])?></td><td>Pag. <?=h($r['page_number'])?> fila <?=h($r['row_number'])?></td><td><?=h($r['review_status'])?></td><td><form method="post"><input type="hidden" name="accion" value="estado"><input type="hidden" name="id" value="<?=h($r['id'])?>"><select name="estado"><option value="pendiente">pendiente</option><option value="validado">validado</option><option value="ignorado">ignorado</option></select><input name="nota" placeholder="nota"><button>Actualizar</button></form></td></tr><?php endforeach;?></tbody></table></section></main></body></html>
